3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	function quoteItem(item: { type: string }): number {
14	  const basePremium = BASE_PREMIUM_BY_ITEM_TYPE[item.type];
15	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
16	  return basePremium + firstInsurance;
17	}
18	
19	export function runScenario(scenario: any): unknown {
20	  const items = scenario.items ?? [];
21	  const itemsTotal = items.length === 0 ? 0 : quoteItem(items[0]);
22	  return { premium: itemsTotal + PROCESSING_FEE };
23	}
